export type ExperienceItem = {
  name: string;
  itemID: number;
  skill: string;
  category: string;
  itemIds: number[];
  byDose: boolean;
};

export type Activity = {
  name: string;
  icon: number;
  displayName: string;
  level: number;
  xp: number;
  rngActivity: boolean;
  experienceItem: string;
  skill: string;
  secondaries: string | null;
  output: { id: number; qty: number } | null;
  linkedItem: string | null;
};

export type Secondary = {
  type: string;
  items?: Array<{ id: number; qty: number }>;
  doseItemIds?: number[];
};

export type Modifier = {
  skill: string;
  name: string;
  type: string;
  multiplier?: number;
  savePercentage?: number;
  baseBonus?: number;
  included: string[];
  ignored: string[];
  tooltip?: string;
};

