// Helper: get level for XP
export function getLevelForXp(xp: number): number {
  for (let i = XP_TABLE.length - 1; i >= 1; i--) {
    if (xp >= XP_TABLE[i]) return i;
  }
  return 1;
}

// Helper: get XP for level
export function getXpForLevel(level: number): number {
  return XP_TABLE[Math.min(level, XP_TABLE.length - 1)] || 0;
}

// Helper: get activities for an experience item
export function getActivitiesForItem(experienceItemName: string): Activity[] {
  return ACTIVITIES.filter((activity) => activity.experienceItem === experienceItemName) as Activity[];
}

// Helper: get experience items for a skill
export function getExperienceItemsForSkill(skill: string): ExperienceItem[] {
  return Object.values(EXPERIENCE_ITEMS).filter((item) => item.skill === skill) as ExperienceItem[];
}
