import { BaseElement } from "../base-element/base-element";
import { storage } from "../data/storage";

type RouteLike = Element & {
  getAttribute(qualifiedName: string): string | null;
};

export class AppNavigation extends BaseElement {
  html(): string {
    const group = storage.getGroup();
    return `<h4 class="app-navigation__group-name">${group.groupName}</h4>
<nav class="app-navigation__nav">
  <men-link link-href="/group/home">
    <button class="men-button" type="button" route-component="home-page">
      <span class="desktop">Home</span>
      <span class="mobile"><img loading="lazy" src="/images/home_teleport.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/items">
    <button class="men-button" type="button" route-component="items-page">
      <span class="desktop">Items</span>
      <span class="mobile"><img loading="lazy" src="/ui/777-0.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/map">
    <button class="men-button" type="button" route-component="map-page">
      <span class="desktop">Map</span>
      <span class="mobile"><img loading="lazy" src="/ui/1698-0.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/graphs">
    <button class="men-button" type="button" route-component="skills-graphs">
      <span class="desktop">Graphs</span>
      <span class="mobile"><img loading="lazy" src="/ui/3579-0.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/panels">
    <button class="men-button" type="button" route-component="panels-page">
      <span class="desktop">Panels</span>
      <span class="mobile"><img loading="lazy" src="/ui/1707-0.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/dps">
    <button class="men-button" type="button" route-component="dps-calc">
      <span class="desktop">DPS</span>
      <span class="mobile"><img loading="lazy" src="/ui/198-0.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/banked-xp">
    <button class="men-button" type="button" route-component="banked-xp-page">
      <span class="desktop">Banked XP</span>
      <span class="mobile"><img loading="lazy" src="/ui/205-0.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/clues">
    <button class="men-button" type="button" route-component="stash-page">
      <span class="desktop">Clues</span>
      <span class="mobile"><img loading="lazy" src="/images/summary-icons/clue_scrolls_all.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/events">
    <button class="men-button" type="button" route-component="events-page">
      <span class="desktop">Events</span>
      <span class="mobile"><img loading="lazy" src="/ui/776-0.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/blog">
    <button class="men-button" type="button" route-component="blog-page">
      <span class="desktop">Blog</span>
      <span class="mobile"><img loading="lazy" src="/ui/1298-0.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/group/settings">
    <button class="men-button" type="button" route-component="group-settings">
      <span class="desktop">Settings</span>
      <span class="mobile"><img loading="lazy" src="/ui/785-0.png" /></span>
    </button>
  </men-link>

  <div class="app-navigation__separator desktop"></div>
  <men-link link-href="/setup-instructions">
    <button class="men-button" type="button">
      <span class="desktop">Setup</span>
      <span class="mobile"><img loading="lazy" src="/ui/1094-0.png" /></span>
    </button>
  </men-link>
  <men-link link-href="/logout">
    <button class="men-button" type="button">
      <span class="desktop">Logout</span>
      <span class="mobile"><img loading="lazy" src="/ui/225-0.png" /></span>
    </button>
  </men-link>
  <donate-button></donate-button>
</nav>
`;
  }

  connectedCallback(): void {
    super.connectedCallback();
    this.render();
    this.subscribe("route-activated", this.handleRouteActivated.bind(this));
  }

  handleRouteActivated(route: unknown): void {
    if (!(route instanceof Element)) {
      return;
    }

    const routeComponent = (route as RouteLike).getAttribute("route-component");
    const buttons = Array.from(this.querySelectorAll("button"));
    for (const button of buttons) {
      const component = button.getAttribute("route-component");
      if (routeComponent === component) {
        button.classList.add("active");
      } else {
        button.classList.remove("active");
      }
    }
  }
}

customElements.define("app-navigation", AppNavigation);