import { BaseElement } from "../base-element/base-element";

export class SidePanel extends BaseElement {
  sidePanels: HTMLElement | null;

  constructor() {
    super();
    this.sidePanels = null;
  }

  html() {
    return `<div class="side-panel__panels"></div>
`;
  }

  connectedCallback() {
    super.connectedCallback();
    this.render();
    this.sidePanels = this.querySelector<HTMLElement>(".side-panel__panels");
    this.subscribe("members-updated", this.handleUpdatedMembers.bind(this));
  }

  disconnectedCallback() {
    super.disconnectedCallback();
  }

  handleUpdatedMembers(members: Array<{ name: string }>) {
    if (!this.sidePanels) {
      return;
    }

    let playerPanels = "";
    for (const member of members) {
      if (member.name === "@SHARED") {
        continue;
      }
      playerPanels += `<player-panel class="rsborder rsbackground" player-name="${member.name}"></player-panel>`;
    }

    this.sidePanels.innerHTML = playerPanels;
  }
}
customElements.define("side-panel", SidePanel);
